(() => {
  // Remove any previous zoom style we added
  const existing = document.getElementById('webbrain-zoom-style');
  if (existing) existing.remove();

  // Determine current zoom level (default 1)
  let currentZoom = 1;
  if (existing) {
    const m = existing.textContent.match(/zoom:\s*([\d.]+)/);
    if (m) currentZoom = parseFloat(m[1]);
  }

  // Increase by 25% each time, cap at 2x
  const newZoom = Math.min(currentZoom * 1.25, 2);

  const style = document.createElement('style');
  style.id = 'webbrain-zoom-style';
  style.textContent = `html { zoom: ${newZoom} !important; }`;
  document.head.appendChild(style);

  return { previousZoom: currentZoom, newZoom };
})();
